public bool CheckValue(HashSet<int> numbers, int value)
{
    // Compliant: using Contains for O(1) lookup in HashSet
    return numbers.Contains(value);
}

public bool CheckString(List<string> items, string search)
{
    // Compliant: Contains uses optimized EqualityComparer
    return items.Contains(search);
}

public bool CheckComplex(List<Customer> customers, int targetAge)
{
